<template>
    <div id="box-container">
        <div v-bind:class="{ is: e3, green: e4 }" class="box not">~ deployed</div>
        <div v-bind:class="{ is: e2 }" class="box not">~ built</div>
        <div v-bind:class="{ is: e1 }" class="box not">~ coded</div>
    </div>
</template>

<script>
export default {
    name: "Anim",
    data: function () {
        return {
            e1: false,
            e2: false,
            e3: false,
            e4: false
        }
    },
    methods: {
        up4: function(){
            this.e4 = true
        },
        up3: function(){
            this.e3 = true
        },
        up2: function(){
            this.e2 = true
        },
        up1: function(){
            this.e1 = true
        }
    },
    mounted() {
        setTimeout(() => {
            this.up1()
        }, 1000);
        setTimeout(() => {
            this.up2()
        }, 3000);
        setTimeout(() => {
            this.up3()
        }, 5000);
        setTimeout(() => {
            this.up4()
        }, 6000);
    }
}
</script>

